const raw = items[0]?.json || {};
const event = raw.body && typeof raw.body === 'object' && !Array.isArray(raw.body) ? raw.body : raw;
const payload = event.payload && typeof event.payload === 'object' && !Array.isArray(event.payload) ? event.payload : event;
const requestId = payload.request_id || payload.requestId || event.request_id || event.requestId;
const goal = payload.goal || event.goal;
const audience = payload.audience || event.audience;
if (!requestId) throw new Error('Missing request_id / requestId');
if (!goal) throw new Error('Missing goal');
if (!audience) throw new Error('Missing audience');
return [{
  json: {
    meta: {
      workflow_name: 'Growth_Asset_Flow',
      timestamp: new Date().toISOString(),
      trigger_source: event.trigger_source || raw.trigger_source || 'campaign_request_webhook',
      risk_level: event.risk_level || raw.risk_level || 'medium'
    },
    context: {
      canonical_links: [
        '[[08-Runbooks/Growth/Campaign-Workflow|Campaign Workflow]]',
        '[[Growth/Creative/Approved-Claims-and-Angles|Approved Claims and Angles]]'
      ],
      constraints: [
        'Do not invent unsupported product claims',
        'Do not publish final assets automatically'
      ]
    },
    payload: {
      request_id: String(requestId),
      campaign_name: String(payload.campaign_name || payload.campaignName || event.campaign_name || event.campaignName || ''),
      goal: String(goal),
      audience: String(audience),
      channel: String(payload.channel || event.channel || ''),
      current_offer_link: String(payload.current_offer_link || payload.currentOfferLink || event.current_offer_link || event.currentOfferLink || ''),
      product_truth_links: Array.isArray(payload.product_truth_links) ? payload.product_truth_links : [],
      known_objections: Array.isArray(payload.known_objections) ? payload.known_objections : [],
      approved_claims_link: String(payload.approved_claims_link || payload.approvedClaimsLink || event.approved_claims_link || event.approvedClaimsLink || ''),
      need_static_creatives: Boolean(payload.need_static_creatives ?? payload.needStaticCreatives ?? event.need_static_creatives ?? event.needStaticCreatives ?? true),
      need_video_brief: Boolean(payload.need_video_brief ?? payload.needVideoBrief ?? event.need_video_brief ?? event.needVideoBrief ?? true),
      brand_direction: Array.isArray(payload.brand_direction) ? payload.brand_direction : ['clean', 'modern', 'trustworthy'],
      formats: Array.isArray(payload.formats) ? payload.formats : ['1080x1350', '1200x628']
    }
  }
}];

const item = items[0]?.json || {};
const required = ['agent', 'workflow', 'status', 'request_id', 'creative_requested', 'video_requested', 'escalate_to', 'reason', 'next_step'];
for (const key of required) {
  if (!(key in item)) throw new Error(`Missing required key: ${key}`);
}
const allowedStatus = new Set(['done', 'partial', 'blocked', 'needs_review', 'queued']);
if (!allowedStatus.has(item.status)) throw new Error(`Invalid status: ${item.status}`);
const allowedEscalation = new Set(['none', 'AI-1', 'AI-2', 'AI-3', 'AI-5', 'AI-6', 'AI-7', 'AI-8', 'AI-9', 'AI-10', 'AI-11', 'Owner']);
if (!allowedEscalation.has(item.escalate_to)) throw new Error(`Invalid escalate_to: ${item.escalate_to}`);
item.execution_summary = {
  growth_ready: !!item.growth_brief,
  creative_generated: !!item.creative_output,
  video_generated: !!item.video_output
};
return [{ json: item }];
